insert into prompts (id,role,objective,level,title,description,content) values ('p001','Formateur','Concevoir','Avancé','Créer un déroulé pédagogique complet','Prompt Formateur prêt à l’emploi.','Agis comme un ingénieur pédagogique. Crée une séquence sur [thème] pour [public], durée [durée]. Inclue objectifs, phases, consignes, activité, critères, évaluation, matériel.') on conflict (id) do nothing;
insert into prompts (id,role,objective,level,title,description,content) values ('p002','Formateur','Évaluer','Intermédiaire','Créer une grille d’évaluation','Prompt Formateur prêt à l’emploi.','Crée une grille pour évaluer [compétence] avec critères observables, niveaux, indicateurs et remédiations.') on conflict (id) do nothing;
insert into prompts (id,role,objective,level,title,description,content) values ('p003','Dirigeant','Organiser','Avancé','Créer une procédure interne','Prompt Dirigeant prêt à l’emploi.','Crée une procédure pour [processus] : objectif, périmètre, responsabilités, étapes, contrôles, erreurs, indicateurs.') on conflict (id) do nothing;
insert into prompts (id,role,objective,level,title,description,content) values ('p004','Dirigeant','Décider','Avancé','Analyser une décision business','Prompt Dirigeant prêt à l’emploi.','Analyse [décision] : avantages, risques, alternatives, coûts cachés, critères et recommandation.') on conflict (id) do nothing;
insert into prompts (id,role,objective,level,title,description,content) values ('p005','Commercial','Vendre','Intermédiaire','Créer un argumentaire commercial','Prompt Commercial prêt à l’emploi.','Crée un argumentaire pour vendre [offre] à [cible] : problème, bénéfices, preuves, objections, réponses.') on conflict (id) do nothing;
insert into prompts (id,role,objective,level,title,description,content) values ('p006','Communication','Publier','Intermédiaire','Post LinkedIn professionnel','Prompt Communication prêt à l’emploi.','Rédige un post LinkedIn sur [sujet] : accroche, contexte, valeur, exemple, conclusion, question.') on conflict (id) do nothing;
insert into prompts (id,role,objective,level,title,description,content) values ('p007','Administratif','Gagner du temps','Débutant','Compte rendu structuré','Prompt Administratif prêt à l’emploi.','Transforme ces notes [notes] en compte rendu avec décisions, actions, responsables, échéances.') on conflict (id) do nothing;
insert into prompts (id,role,objective,level,title,description,content) values ('p008','Sécurité','Sécuriser','Intermédiaire','Anonymiser un contenu','Prompt Sécurité prêt à l’emploi.','Anonymise [contenu] en supprimant noms, coordonnées, données sensibles et éléments identifiants.') on conflict (id) do nothing;
insert into prompts (id,role,objective,level,title,description,content) values ('p009','Management','Former','Avancé','Simplifier une fiche mémo','Modèle prêt à l’emploi pour une fiche mémo.','Simplifie [une fiche mémo] pour un public non expert. Garde l’essentiel, ajoute exemple, supprime jargon et termine par checklist.') on conflict (id) do nothing;
